#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define STR_SIZE 256

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

void random_matrix(float *I, int rows, int cols);
void runTest( int argc, char** argv);

void usage(int argc, char **argv)
{
	fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <lamda> <no. of iter>\n", argv[0]);
	fprintf(stderr, "\t<rows>   - number of rows\n");
	fprintf(stderr, "\t<cols>    - number of cols\n");
	fprintf(stderr, "\t<y1> 	 - y1 value of the speckle\n");
	fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
	fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
	fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
	fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
	fprintf(stderr, "\t<no. of iter>   - number of iterations\n");
	exit(1);
}

// OpenMP version of srad_cuda_1
void srad_omp_1(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float q0sqr)
{
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;

            float jc = J_cuda[index];

            float n_val, s_val, w_val, e_val;

            if (i == 0)
                n_val = J_cuda[j] - jc;
            else
                n_val = J_cuda[(i-1) * cols + j] - jc;

            if (i == rows - 1)
                s_val = J_cuda[(rows-1) * cols + j] - jc;
            else
                s_val = J_cuda[(i+1) * cols + j] - jc;

            if (j == 0)
                w_val = J_cuda[i * cols + 0] - jc;
            else
                w_val = J_cuda[i * cols + (j-1)] - jc;

            if (j == cols - 1)
                e_val = J_cuda[i * cols + (cols-1)] - jc;
            else
                e_val = J_cuda[i * cols + (j+1)] - jc;

            float g2 = (n_val * n_val + s_val * s_val + w_val * w_val + e_val * e_val) / (jc * jc);
            float l  = (n_val + s_val + w_val + e_val) / jc;

            float num  = (0.5f * g2) - ((1.0f / 16.0f) * (l * l));
            float den  = 1.0f + (0.25f * l);
            float qsqr = num / (den * den);

            den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
            float c_val = 1.0f / (1.0f + den);

            if (c_val < 0.0f)       c_val = 0.0f;
            else if (c_val > 1.0f)  c_val = 1.0f;

            C_cuda[index] = c_val;
            E_C[index] = e_val;
            W_C[index] = w_val;
            S_C[index] = s_val;
            N_C[index] = n_val;
        }
    }
}

// OpenMP version of srad_cuda_2
void srad_omp_2(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float lambda,
    float q0sqr)
{
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;

            float cc = C_cuda[index];

            float cn, cs, cw, ce;

            cn = cc;
            cw = cc;

            if (i == rows - 1)
                cs = C_cuda[(rows-1) * cols + j];
            else
                cs = C_cuda[(i+1) * cols + j];

            if (j == cols - 1)
                ce = C_cuda[i * cols + (cols-1)];
            else
                ce = C_cuda[i * cols + (j+1)];

            float d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];

            J_cuda[index] = J_cuda[index] + 0.25f * lambda * d_sum;
        }
    }
}

int main(int argc, char** argv)
{
    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    runTest(argc, argv);
    return EXIT_SUCCESS;
}

void runTest(int argc, char** argv)
{
    int rows, cols, size_I, size_R, niter = 10, iter;
    float *I, *J, lambda, q0sqr, sum, sum2, tmp, meanROI, varROI;

    float *J_cuda;
    float *C_cuda;
    float *E_C, *W_C, *N_C, *S_C;

    unsigned int r1, r2, c1, c2;
    float *c;

    if (argc == 9)
    {
        rows   = atoi(argv[1]);
        cols   = atoi(argv[2]);
        if ((rows % 16 != 0) || (cols % 16 != 0)) {
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1     = atoi(argv[3]);
        r2     = atoi(argv[4]);
        c1     = atoi(argv[5]);
        c2     = atoi(argv[6]);
        lambda = atof(argv[7]);
        niter  = atoi(argv[8]);
    }
    else {
        usage(argc, argv);
        return;
    }

    size_I = cols * rows;
    size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

    I = (float *)malloc(size_I * sizeof(float));
    J = (float *)malloc(size_I * sizeof(float));
    c = (float *)malloc(sizeof(float) * size_I);

    J_cuda = (float *)malloc(sizeof(float) * size_I);
    C_cuda = (float *)malloc(sizeof(float) * size_I);
    E_C    = (float *)malloc(sizeof(float) * size_I);
    W_C    = (float *)malloc(sizeof(float) * size_I);
    S_C    = (float *)malloc(sizeof(float) * size_I);
    N_C    = (float *)malloc(sizeof(float) * size_I);

    printf("Randomizing the input matrix\n");
    random_matrix(I, rows, cols);

    for (int k = 0; k < size_I; k++) {
        J[k] = (float)exp(I[k]);
    }

    printf("Start the SRAD main loop\n");

    for (iter = 0; iter < niter; iter++) {
        sum  = 0;
        sum2 = 0;
        for (int i = r1; i <= (int)r2; i++) {
            for (int j = c1; j <= (int)c2; j++) {
                tmp   = J[i * cols + j];
                sum  += tmp;
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI  = (sum2 / size_R) - meanROI * meanROI;
        q0sqr   = varROI / (meanROI * meanROI);

        // Copy J to J_cuda
        memcpy(J_cuda, J, sizeof(float) * size_I);

        // Run OpenMP kernels
        srad_omp_1(E_C, W_C, N_C, S_C, J_cuda, C_cuda, cols, rows, q0sqr);
        srad_omp_2(E_C, W_C, N_C, S_C, J_cuda, C_cuda, cols, rows, lambda, q0sqr);

        // Copy result back
        memcpy(J, J_cuda, sizeof(float) * size_I);
    }

#ifdef OUTPUT
    printf("Printing Output:\n");
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%.5f ", J[i * cols + j]);
        }
        printf("\n");
    }
#endif

    printf("Computation Done\n");

    free(I);
    free(J);
    free(J_cuda);
    free(C_cuda);
    free(E_C);
    free(W_C);
    free(N_C);
    free(S_C);
    free(c);
}

void random_matrix(float *I, int rows, int cols)
{
    srand(7);
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            I[i * cols + j] = rand() / (float)RAND_MAX;
        }
    }
}
